import { MakeLogicType, connect, kea, key, path, props } from 'kea'
import { router, urlToAction } from 'kea-router'

import { eventUsageLogic } from 'lib/utils/eventUsageLogic'
import { urls } from 'scenes/urls'

import type { Survey } from '../../../types'
import { surveysLogic } from '../surveysLogic'

export interface SurveyFormBuilderLogicProps {
    id: string // 'new' for new surveys, or a UUID for editing
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface surveyFormBuilderLogicValues {
    formBuilderEnabled: boolean // surveysLogic
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface surveyFormBuilderLogicActions {
    reportSurveyCreated: (
        survey: Survey,
        isDuplicate?: boolean,
        creationSource?: 'form_builder' | 'full_editor' | 'llm_analytics' | 'quick_create' | 'template' | 'wizard'
    ) => {
        creationSource:
            | 'form_builder'
            | 'full_editor'
            | 'llm_analytics'
            | 'quick_create'
            | 'template'
            | 'wizard'
            | undefined
        isDuplicate: boolean | undefined
        survey: Survey
    } // eventUsageLogic
    reportSurveyEdited: (survey: Survey) => {
        survey: Survey
    } // eventUsageLogic
    loadSurveys: () => any // surveysLogic
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface surveyFormBuilderLogicMeta {
    key: string
}

export type surveyFormBuilderLogicType = MakeLogicType<
    surveyFormBuilderLogicValues,
    surveyFormBuilderLogicActions,
    SurveyFormBuilderLogicProps,
    surveyFormBuilderLogicMeta
>

export const surveyFormBuilderLogic = kea<surveyFormBuilderLogicType>([
    path(['scenes', 'surveys', 'form', 'surveyFormBuilderLogic']),

    props({} as SurveyFormBuilderLogicProps),

    key((props) => props.id),

    connect(() => ({
        actions: [surveysLogic, ['loadSurveys'], eventUsageLogic, ['reportSurveyCreated', 'reportSurveyEdited']],
        values: [surveysLogic, ['formBuilderEnabled']],
    })),

    urlToAction(({ values, props }) => ({
        [urls.surveyFormBuilder(props.id)]: () => {
            if (!values.formBuilderEnabled) {
                router.actions.replace(urls.survey(props.id))
            }
        },
    })),
])
